#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Entities;
using MVZ2.Vanilla.Entities;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.skeletonStatue_State)]
    public class SkeletonStatue_StateBehaviour : EnemyStateBehaviour
    {
        public SkeletonStatue_StateBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        protected override int GetPassiveState(Entity enemy)
        {
            if (SkeletonStatue.IsReviving(enemy))
            {
                return SkeletonStatue.STATE_REVIVING;
            }
            return base.GetPassiveState(enemy);
        }
        protected override int GetActiveState(Entity enemy)
        {
            if (enemy.HasBuff<StoneEyeSlowingBuff>())
                return STATE_IDLE;
            return base.GetActiveState(enemy);
        }
    }
}
